{
    Console.WriteLine($"[{w.ProjectFile}] {w.File}({w.LineNumber},{w.ColumnNumber}): warning {w.Code}: {w.Text}");
}

// Check project build results
Console.WriteLine("\n=== PROJECT BUILD RESULTS ===");
var projects = build.FindChildrenRecursive<Project>();
foreach (var p in projects)
{
    Console.WriteLine($"  {p.Name} - Succeeded: {p.Succeeded}");
}
EOF

