cd /tmp/binlog_parser && cat > Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild(args[0]);
var errors = build.FindChildrenRecursive<Error>();

Console.WriteLine("=== ALL ERRORS GROUPED BY PROJECT ===");
foreach (var group in errors.GroupBy(e => e.ProjectFile))
{
    Console.WriteLine($"\nProject: {group.Key}");
    foreach (var e in group)
    {
        Console.WriteLine($"  {e.File}({e.LineNumber},{e.ColumnNumber}): error {e.Code}: {e.Text}");
    }
}

// Check if Api had its own compile errors
Console.WriteLine("\n=== CHECKING FOR MSB ERRORS ===");
var messages = build.FindChildrenRecursive<Message>().Where(m => m.Text != null && m.Text.Contains("MSB3202")).ToList();
foreach (var m in messages) Console.WriteLine($"  {m.Text}");

// Look for "could not be resolved" type errors for project references  
var allItems = build.FindChildrenRecursive<Item>().Where(i => i.Text != null && i.Text.Contains("Services")).Take(5);
foreach (var i in allItems) Console.WriteLine($"  Item: {i.Text}");
EOF
